const MEMORY_FILE = './DADOS DO CORVO/ai_memory.json';
const CONTEXT_FILE = './DADOS DO CORVO/ai_contexts.json';

function getLocalData(file) {
  try {
    if (!fs.existsSync(file)) return {};
    return JSON.parse(fs.readFileSync(file, 'utf-8'));
  } catch (e) {
    return {};
  }
}

function saveLocalData(file, data) {
  try {
    const dir = path.dirname(file);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(file, JSON.stringify(data, null, 2));
  } catch (e) {
    console.error(`[LOCAL-SAVE-ERROR] ${file}`, e.message);
  }
}

async function saveAiMessageLocal(from, role, content, pushname, groupName) {
  const data = getLocalData(MEMORY_FILE);
  if (!data[from]) data[from] = [];
  data[from].push({
    role,
    content,
    pushname: pushname || 'Desconhecido',
    groupName: groupName || 'PV',
    timestamp: Date.now()
  });
  saveLocalData(MEMORY_FILE, data);
}

async function getAiMemoryLocal(from, maxLines = 50) {
  const data = getLocalData(MEMORY_FILE);
  if (!data[from]) return [];
  return data[from].slice(-maxLines);
}

async function resetAiMemoryLocal(from) {
  const memData = getLocalData(MEMORY_FILE);
  if (memData[from]) {
    delete memData[from];
    saveLocalData(MEMORY_FILE, memData);
  }

  const ctxData = getLocalData(CONTEXT_FILE);
  ctxData[from] = { resetFlag: true, ownerPreferredName: setting.ownerName || "Mestre" };
  saveLocalData(CONTEXT_FILE, ctxData);
  return true;
}

async function getAiContextLocal(from) {
  const data = getLocalData(CONTEXT_FILE);
  if (data[from]) return data[from];
  return { ownerPreferredName: setting.ownerName || "Mestre", resetFlag: true };
}

async function saveAiContextLocal(from, context) {
  const data = getLocalData(CONTEXT_FILE);
  data[from] = context;
  saveLocalData(CONTEXT_FILE, data);
}
