function loadJson(file, fallback = {}) {
  try {
    if (!fs.existsSync(file)) {
      fs.writeFileSync(file, JSON.stringify(fallback, null, 2))
      return fallback
    }
    return JSON.parse(fs.readFileSync(file))
  } catch (err) {
    console.log("ERRO loadJson:", file, err)
    return fallback
  }
}

function saveJson(file, data) {
  try {
    fs.writeFileSync(file, JSON.stringify(data, null, 2))
  } catch (err) {
    console.log("ERRO saveJson:", file, err)
  }
}

const PATH_AUTORPG = "./database/usuarios/SystemRPG/autorpg.json";
const PATH_SABRPG = "./database/usuarios/SystemRPG/sabrpg.json";
const PATH_CODERPG = "./database/usuarios/SystemRPG/coderpg.json";

let autorpg = loadJson(PATH_AUTORPG, []);
let sabrpg = loadJson(PATH_SABRPG, []);
let coderpg = loadJson(PATH_CODERPG, []);

if (!Array.isArray(autorpg)) autorpg = [];
if (!Array.isArray(sabrpg)) sabrpg = [];
if (!Array.isArray(coderpg)) coderpg = [];

function isRpgOn(groupId) {
  const item = autorpg.find(i => i.id === groupId);
  return item?.rpg === true;
}

function setRpgOn(groupId, value) {
  const idx = autorpg.findIndex(i => i.id === groupId);
  if (idx === -1) autorpg.push({ id: groupId, rpg: !!value });
  else autorpg[idx].rpg = !!value;
  saveJson(PATH_AUTORPG, autorpg);
}

function getUserIndex(arr, id) {
  return arr.findIndex(i => i.id === id);
}

function moneyBR(n) {
  return Number(n || 0).toLocaleString("pt-BR", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function clamp(n, min, max) { return Math.max(min, Math.min(max, n)); }
function randInt(min, max) { return Math.floor(Math.random() * (max - min + 1)) + min; }
function chanceRoll(percent) { return Math.random() * 100 < Number(percent || 0); }

function ensureUserRPG(user) {
  if (user.money == null) user.money = 0;
  if (user.xp == null) user.xp = 0;

  // emprego
  if (user.jobId == null) user.jobId = null;
  if (user.jobName == null) user.jobName = "Desempregado";
  if (user.pendingJobId == null) user.pendingJobId = null; // id escolhido em +emprego <id>
  if (user.pendingJobName == null) user.pendingJobName = null;
  if (user.pendingChance == null) user.pendingChance = null;

  // cooldowns
  if (user.lastCurriculo == null) user.lastCurriculo = 0;
  if (user.lastWork == null) user.lastWork = 0;

  // inventário
  if (!Array.isArray(user.armas)) user.armas = [];
  if (user.armaEquipada == null) user.armaEquipada = null;

  if (!Array.isArray(user.pets)) user.pets = [];
  if (user.petEquipado == null) user.petEquipado = null;
}

function getUserRPG(sender, from) {
  // aqui você decide: salvar por usuário global (recomendado)
  // se você quiser por grupo, salva com key `${from}|${sender}`
  const id = sender;

  let idx = getUserIndex(sabrpg, id);
  if (idx === -1) return { ok: false, idx: -1, user: null };

  ensureUserRPG(sabrpg[idx]);
  // garante que tem grupo de registro
  if (!sabrpg[idx].gpid) sabrpg[idx].gpid = from;
  return { ok: true, idx, user: sabrpg[idx] };
}

function saveSabrpg() {
  saveJson(PATH_SABRPG, sabrpg);
}

