                var horas = Math.floor((restante / (1000 * 60 * 60)) % 24)
                var minutos = Math.floor((restante / (1000 * 60)) % 60)
                texto += `• *${i + 1}.* ✨ *${nome}*\n• 🔗 ʟɪɴᴋ: ${link}\n• 👤 ᴍᴇᴍʙʀᴏs: ${membros}\n• ⏳ ᴛᴇᴍᴘᴏ ʀᴇsᴛᴀɴᴛᴇ: ${dias}d ${horas}h ${minutos}m\n─────────────────────────────\n`
