            if (isJidBot(menc_os2)) return reply(`*ɴᴀᴏ ᴘᴏssᴏ ᴍᴜᴛᴀʀ ᴏ ʙᴏᴛ 😵*`);
            if (numerodono.some(d => d.split('@')[0] === menc_os2.split('@')[0])) return reply(`*ɴᴀᴏ ᴏᴜsᴇ ᴛᴏᴄᴀʀ ɴᴏ ᴍᴇᴜ ᴅᴏɴᴏ 💢*`);
            if (vip.map(i => i.id).includes(menc_os2) || vip.map(i => i.id.split('@')[0]).includes(menc_os2.split('@')[0])) return reply(`*ɴᴀᴏ ᴍᴇxᴀ ᴄᴏᴍ ǫᴜᴇᴍ ᴇ ᴠɪᴘ 😎*`);
            if (isJidAdmin(menc_os2)) return reply(`*ɴᴀᴏ ᴘᴏᴅᴇ ᴍᴜᴛᴀʀ ᴜᴍ ᴀᴅᴍɪɴ*`);

            var tipo = q.toLowerCase().includes("silenciar") ? "silenciar" : "mutar";

