                      var descMatch = htmlStr.match(/<meta[^>]*property=["']og:description["'][^>]*content=["']([^"']+)["']/i) || htmlStr.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']/i)
                      var imgMatch = htmlStr.match(/<meta[^>]*property=["']og:image["'][^>]*content=["']([^"']+)["']/i)
